import { create } from "zustand";

interface UndoAction {
  /** What was deleted (e.g. "Chat: My Adventure") */
  label: string;
  /** Async callback to restore the deleted item */
  onUndo: () => Promise<void>;
}

interface UndoState {
  /** Currently pending undo action, or null */
  pending: UndoAction | null;
  /** Timer id for auto-dismiss */
  timerId: ReturnType<typeof setTimeout> | null;
  /** Show an undo toast */
  show: (action: UndoAction) => void;
  /** Execute undo and clear the toast */
  undo: () => Promise<void>;
  /** Dismiss the toast without undoing */
  dismiss: () => void;
}

const TOAST_DURATION_MS = 5000;

export const useUndoStore = create<UndoState>((set, get) => ({
  pending: null,
  timerId: null,
  show: (action) => {
    const prev = get().timerId;
    if (prev) clearTimeout(prev);
    const timerId = setTimeout(() => {
      set({ pending: null, timerId: null });
    }, TOAST_DURATION_MS);
    set({ pending: action, timerId });
  },
  undo: async () => {
    const { pending, timerId } = get();
    if (timerId) clearTimeout(timerId);
    set({ pending: null, timerId: null });
    if (pending) {
      try {
        await pending.onUndo();
      } catch {
        // Undo failed — not much we can do at the toast level
      }
    }
  },
  dismiss: () => {
    const { timerId } = get();
    if (timerId) clearTimeout(timerId);
    set({ pending: null, timerId: null });
  },
}));

/** Hook that returns a show-undo helper for a given i18n label and undo callback. */
export function useUndoToast() {
  const { show } = useUndoStore();
  return {
    /** Call after deleting an entity — shows the undo toast. */
    toastUndo: (label: string, onUndo: () => Promise<void>) => {
      show({ label, onUndo });
    },
  };
}

import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";

import { checkForUpdate, relaunchApp, type AvailableUpdate } from "../platform";

type Phase = "idle" | "available" | "downloading" | "error";

/**
 * Non-intrusive update notification (M32). Checks GitHub Releases once on
 * startup; when a newer version exists, shows a small toast with an
 * "update now" button. Download + install + signature verification is
 * handled by tauri-plugin-updater; we just relaunch afterwards.
 */
export function UpdateBanner() {
  const { t } = useTranslation();
  const [update, setUpdate] = useState<AvailableUpdate | null>(null);
  const [phase, setPhase] = useState<Phase>("idle");
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    void checkForUpdate().then((u) => {
      if (u) {
        setUpdate(u);
        setPhase("available");
      }
    });
  }, []);

  if (!update || dismissed || phase === "idle") return null;

  const install = async () => {
    setPhase("downloading");
    try {
      await update.downloadAndInstall();
      await relaunchApp();
    } catch (err) {
      console.warn("update failed:", err);
      setPhase("error");
    }
  };

  return (
    <div
      className="fixed bottom-4 right-4 z-50 flex items-center gap-3 rounded-lg px-4 py-3 shadow-lg"
      style={{
        background: "var(--color-surface)",
        border: "1px solid var(--color-border)",
        color: "var(--color-text)",
      }}
    >
      <span className="text-sm">
        {phase === "error"
          ? t("update.error")
          : phase === "downloading"
            ? t("update.downloading")
            : t("update.available", { version: update.version })}
      </span>
      {phase === "available" && (
        <button
          type="button"
          className="rounded px-3 py-1 text-sm font-medium"
          style={{ background: "var(--color-accent)", color: "var(--color-accent-contrast, #fff)" }}
          onClick={() => void install()}
        >
          {t("update.installNow")}
        </button>
      )}
      {phase !== "downloading" && (
        <button
          type="button"
